import{_ as o,c as e,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"配额治理: Quota Protection 与预热 | Antigravity-Manager","description":"学习 Antigravity-Manager 配额治理机制。使用 Quota Protection 按阈值保护模型，Smart Warmup 自动预热，支持定时扫描与冷却控制。","frontmatter":{"title":"配额治理: Quota Protection 与预热 | Antigravity-Manager","subtitle":"配额治理: Quota Protection 与预热 | Antigravity-Manager","sidebarTitle":"保护你的模型配额","description":"学习 Antigravity-Manager 配额治理机制。使用 Quota Protection 按阈值保护模型，Smart Warmup 自动预热，支持定时扫描与冷却控制。","tags":["quota","warmup","accounts","proxy"],"prerequisite":["start-add-account","start-proxy-and-first-client"],"order":5},"headers":[],"relativePath":"zh/lbjlaq/Antigravity-Manager/advanced/quota/index.md","filePath":"zh/lbjlaq/Antigravity-Manager/advanced/quota/index.md"}'),d={name:"zh/lbjlaq/Antigravity-Manager/advanced/quota/index.md"};function c(n,t,i,s,l,u){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="配额治理-quota-protection-smart-warmup-的组合打法" tabindex="-1">配额治理：Quota Protection + Smart Warmup 的组合打法 <a class="header-anchor" href="#配额治理-quota-protection-smart-warmup-的组合打法" aria-label="Permalink to &quot;配额治理：Quota Protection + Smart Warmup 的组合打法&quot;">​</a></h1><p>你用 Antigravity Tools 跑代理跑得挺稳，但最怕的还是一件事：主力模型的配额被&quot;悄悄吃光&quot;，等你真要用的时候才发现已经低到没法打。</p><p>这一课专讲 <strong>配额治理</strong>：用 Quota Protection 把关键模型留住；用 Smart Warmup 在配额回满时做一次&quot;轻量热身&quot;，减少临时掉链子。</p><h2 id="什么是配额治理" tabindex="-1">什么是配额治理？ <a class="header-anchor" href="#什么是配额治理" aria-label="Permalink to &quot;什么是配额治理？&quot;">​</a></h2><p><strong>配额治理</strong>是指在 Antigravity Tools 里用两套联动机制控制&quot;配额怎么花&quot;：当某个模型的剩余配额低到阈值以下时，Quota Protection 会把该模型加入账号的 <code>protected_models</code>，请求该模型时会优先避开；当配额回到 100% 时，Smart Warmup 会触发一次极小流量的预热请求，并用本地历史文件做 4 小时冷却。</p><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>开启 Quota Protection，让低配额账号自动&quot;让路&quot;，把高价值模型留给关键请求</li><li>开启 Smart Warmup，让配额回满后自动预热（并知道 4 小时冷却怎么影响触发频率）</li><li>搞清楚 <code>quota_protection</code> / <code>scheduled_warmup</code> / <code>protected_models</code> 三个字段分别在哪里生效</li><li>知道哪些模型名会被归一化成&quot;保护组&quot;（以及哪些不会）</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><ul><li>你以为自己在&quot;轮换账号&quot;，但其实一直在消耗同一类高价值模型</li><li>配额低了才发现，甚至是 Claude Code/客户端在后台 warmup 把额度啃掉</li><li>你开了预热，但不知道它到底何时触发、有没有冷却、是否会影响配额</li></ul><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><ul><li>你有多个账号池，希望关键模型在&quot;重要时刻&quot;还有余粮</li><li>你不想手动盯着配额回满时间，想让系统自动做&quot;回满后的轻量验证&quot;</li></ul><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">前置条件</p><p>本课默认你已经能：</p><ul><li>在 <strong>Accounts</strong> 页面看到账号列表，并能手动刷新配额</li><li>已经启动过本地反代（至少能访问 <code>/healthz</code>）</li></ul><p>如果还没跑通，先看 <strong><a href="/docs/opencodedocs/zh/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">启动本地反代并接入第一个客户端</a></strong>。</p></div><p>另外，Smart Warmup 会写入本地历史文件 <code>warmup_history.json</code>。它放在数据目录里，数据目录位置和备份方式可以先看 <strong><a href="/docs/opencodedocs/zh/lbjlaq/Antigravity-Manager/start/first-run-data/">首次启动必懂：数据目录、日志、托盘与自动启动</a></strong>。</p><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>这套&quot;组合打法&quot;背后其实很朴素：</p><ul><li>Quota Protection 负责&quot;别再浪费&quot;：当某个模型低于阈值，就把它标记为受保护，请求该模型时优先避开（模型级别，而不是一刀切禁用账号）。</li><li>Smart Warmup 负责&quot;配额回满就验一下&quot;：当模型回到 100% 时，触发一次轻量请求，确认链路可用，并用 4 小时冷却避免反复打扰。</li></ul><p>它们对应的配置字段都在前端的 <code>AppConfig</code> 里：</p><ul><li><code>quota_protection.enabled / threshold_percentage / monitored_models</code>（见 <code>src/types/config.ts</code>）</li><li><code>scheduled_warmup.enabled / monitored_models</code>（见 <code>src/types/config.ts</code>）</li></ul><p>而真正决定&quot;请求该模型时要不要跳过该账号&quot;的逻辑在后端 TokenManager：</p><ul><li>账号文件里的 <code>protected_models</code> 会在 <code>get_token(..., target_model)</code> 里参与过滤（见 <code>src-tauri/src/proxy/token_manager.rs</code>）</li><li><code>target_model</code> 会先做一次归一化（<code>normalize_to_standard_id</code>），所以 <code>claude-sonnet-4-5-thinking</code> 这类变体会被折叠到同一个&quot;保护组&quot;（见 <code>src-tauri/src/proxy/common/model_mapping.rs</code>）</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="/docs/opencodedocs/zh/lbjlaq/Antigravity-Manager/advanced/monitoring/">Proxy Monitor：请求日志、筛选、详情还原与导出</a></strong>，把调用黑盒变成可复盘的证据链。</p></blockquote><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-先把配额刷到-有数" tabindex="-1">第 1 步：先把配额刷到&quot;有数&quot; <a class="header-anchor" href="#第-1-步-先把配额刷到-有数" aria-label="Permalink to &quot;第 1 步：先把配额刷到&quot;有数&quot;&quot;">​</a></h3><p><strong>为什么</strong> Quota Protection 是基于账号的 <code>quota.models[].percentage</code> 做判断的。你配额没刷出来，保护逻辑就没法对你做任何事。</p><p>操作路径：打开 <strong>Accounts</strong> 页面，点工具栏的刷新按钮（单个账号或全量都行）。</p><p><strong>你应该看到</strong>：账号行里出现各模型的配额百分比（例如 0-100）和 reset time。</p><h3 id="第-2-步-在-settings-里打开-smart-warmup-可选-但推荐" tabindex="-1">第 2 步：在 Settings 里打开 Smart Warmup（可选，但推荐） <a class="header-anchor" href="#第-2-步-在-settings-里打开-smart-warmup-可选-但推荐" aria-label="Permalink to &quot;第 2 步：在 Settings 里打开 Smart Warmup（可选，但推荐）&quot;">​</a></h3><p><strong>为什么</strong> Smart Warmup 的目标不是&quot;省配额&quot;，而是&quot;配额回满就自检一下链路&quot;。它只在模型配额到 100% 时触发，而且有 4 小时冷却。</p><p>操作路径：进入 <strong>Settings</strong>，切到账号相关设置区域，打开 <strong>Smart Warmup</strong> 开关，然后勾选你要监控的模型。</p><p>别忘了保存设置。</p><p><strong>你应该看到</strong>：Smart Warmup 展开后出现模型列表；至少保留 1 个模型被勾选。</p><h3 id="第-3-步-打开-quota-protection-并设置阈值与监控模型" tabindex="-1">第 3 步：打开 Quota Protection，并设置阈值与监控模型 <a class="header-anchor" href="#第-3-步-打开-quota-protection-并设置阈值与监控模型" aria-label="Permalink to &quot;第 3 步：打开 Quota Protection，并设置阈值与监控模型&quot;">​</a></h3><p><strong>为什么</strong> Quota Protection 是&quot;留余粮&quot;的核心：当监控模型的配额百分比 <code>&lt;= threshold_percentage</code> 时，会把该模型写进账号文件的 <code>protected_models</code>，后续请求该模型会优先避开这类账号。</p><p>操作路径：在 <strong>Settings</strong> 里打开 <strong>Quota Protection</strong>。</p><ol><li>设置阈值（<code>1-99</code>）</li><li>勾选你要监控的模型（至少 1 个）</li></ol><div class="tip custom-block"><p class="custom-block-title">一个很好用的起手配置</p><p>如果你不想纠结，从默认 <code>threshold_percentage=10</code> 开始就行（见 <code>src/pages/Settings.tsx</code>）。</p></div><p><strong>你应该看到</strong>：Quota Protection 的模型勾选至少保留 1 个（UI 会阻止你把最后一个也取消掉）。</p><h3 id="第-4-步-确认-保护组归一化-不会让你踩坑" tabindex="-1">第 4 步：确认&quot;保护组归一化&quot;不会让你踩坑 <a class="header-anchor" href="#第-4-步-确认-保护组归一化-不会让你踩坑" aria-label="Permalink to &quot;第 4 步：确认&quot;保护组归一化&quot;不会让你踩坑&quot;">​</a></h3><p><strong>为什么</strong> TokenManager 做配额保护判断时，会先把 <code>target_model</code> 归一化成标准 ID（<code>normalize_to_standard_id</code>）。例如 <code>claude-sonnet-4-5-thinking</code> 会被归一到 <code>claude-sonnet-4-5</code>。</p><p>这意味着：</p><ul><li>你在 Quota Protection 里勾选 <code>claude-sonnet-4-5</code></li><li>当你实际请求 <code>claude-sonnet-4-5-thinking</code></li></ul><p>仍然会命中保护（因为它们属于同一组）。</p><p><strong>你应该看到</strong>：当某账号的 <code>protected_models</code> 里包含 <code>claude-sonnet-4-5</code> 时，对 <code>claude-sonnet-4-5-thinking</code> 的请求会优先避开该账号。</p><h3 id="第-5-步-需要立刻验证时-用-手动预热-触发一次-warmup" tabindex="-1">第 5 步：需要立刻验证时，用&quot;手动预热&quot;触发一次 warmup <a class="header-anchor" href="#第-5-步-需要立刻验证时-用-手动预热-触发一次-warmup" aria-label="Permalink to &quot;第 5 步：需要立刻验证时，用&quot;手动预热&quot;触发一次 warmup&quot;">​</a></h3><p><strong>为什么</strong> 定时 Smart Warmup 的扫描周期是 10 分钟一次（见 <code>src-tauri/src/modules/scheduler.rs</code>）。你想立刻验证链路，手动预热更直接。</p><p>操作路径：打开 <strong>Accounts</strong> 页面，点工具栏的&quot;预热&quot;按钮：</p><ul><li>不选账号：触发全量预热（调用 <code>warm_up_all_accounts</code>）</li><li>选中账号：对选中的账号逐个触发预热（调用 <code>warm_up_account</code>）</li></ul><p><strong>你应该看到</strong>：出现 toast，内容来自后端返回的字符串（例如 &quot;Warmup task triggered ...&quot;）。</p><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><ul><li>你能在 Accounts 页面看到每个账号的模型配额百分比（证明配额数据链路 OK）</li><li>你能在 Settings 里打开 Quota Protection / Smart Warmup，并成功保存配置</li><li>你理解 <code>protected_models</code> 是&quot;模型级&quot;限制：一个账号可能只对某些模型被避开</li><li>你知道 warmup 有 4 小时冷却：短时间内重复点预热，可能会看到&quot;skipped/cooldown&quot;相关提示</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="_1-你开了-quota-protection-但一直没生效" tabindex="-1">1) 你开了 Quota Protection，但一直没生效 <a class="header-anchor" href="#_1-你开了-quota-protection-但一直没生效" aria-label="Permalink to &quot;1) 你开了 Quota Protection，但一直没生效&quot;">​</a></h3><p>最常见原因是：账号没有 <code>quota</code> 数据。保护逻辑在后端需要先读取 <code>quota.models[]</code> 才能判断阈值（见 <code>src-tauri/src/proxy/token_manager.rs</code>）。</p><p>你可以回到 <strong>第 1 步</strong>，先把配额刷新出来。</p><h3 id="_2-为什么只有少数模型会被当成-保护组" tabindex="-1">2) 为什么只有少数模型会被当成&quot;保护组&quot;？ <a class="header-anchor" href="#_2-为什么只有少数模型会被当成-保护组" aria-label="Permalink to &quot;2) 为什么只有少数模型会被当成&quot;保护组&quot;？&quot;">​</a></h3><p>TokenManager 对 <code>target_model</code> 的归一化是&quot;白名单式&quot;的：只有明确列出来的模型名才会被映射到标准 ID（见 <code>src-tauri/src/proxy/common/model_mapping.rs</code>）。</p><p>归一化后的逻辑是：用归一化后的名称（标准 ID 或原始模型名）去匹配账号的 <code>protected_models</code> 字段。如果匹配成功，该账号会被跳过（见 <code>src-tauri/src/proxy/token_manager.rs:555-560, 716-719</code>）。这意味着：</p><ul><li>白名单内的模型（如 <code>claude-sonnet-4-5-thinking</code>）会被归一化为标准 ID（<code>claude-sonnet-4-5</code>），然后判断是否在 <code>protected_models</code> 中</li><li>白名单外的模型归一化失败时，回退到原始模型名，仍然会去匹配 <code>protected_models</code></li></ul><p>换句话说，配额保护判断对&quot;所有模型名&quot;都生效，只是白名单内的模型会先归一化。</p><h3 id="_3-手动-定时预热为什么需要代理在跑" tabindex="-1">3) 手动/定时预热为什么需要代理在跑？ <a class="header-anchor" href="#_3-手动-定时预热为什么需要代理在跑" aria-label="Permalink to &quot;3) 手动/定时预热为什么需要代理在跑？&quot;">​</a></h3><p>预热请求最终会打到本地代理的内部端点：<code>POST /internal/warmup</code>（见 <code>src-tauri/src/proxy/server.rs</code> 的路由，以及 <code>src-tauri/src/proxy/handlers/warmup.rs</code> 的实现）。如果你没启动代理服务，warmup 会失败。</p><p>另外，预热调用的端口来自配置：<code>proxy.port</code>（如果读取配置失败，会回退到 <code>8045</code>，见 <code>src-tauri/src/modules/quota.rs</code>）。</p><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><ul><li>Quota Protection 做&quot;止损&quot;：阈值以下就把模型写进 <code>protected_models</code>，请求该模型时优先避开</li><li>Smart Warmup 做&quot;回满自检&quot;：只在 100% 时触发，10 分钟扫描一次，4 小时冷却</li><li>两者都依赖&quot;配额刷新&quot;链路：先有 <code>quota.models[]</code>，治理才有基础</li></ul><h2 id="下一课预告-1" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告-1" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><p>配额治理解决的是&quot;怎么花更稳&quot;。下一课建议接着看 <strong>Proxy Monitor</strong>，把请求日志、账号命中、模型映射都变成可回放的证据链。</p><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>Quota Protection UI（阈值、模型勾选、至少保留 1 个）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/QuotaProtection.tsx#L13-L168" target="_blank" rel="noreferrer"><code>src/components/settings/QuotaProtection.tsx</code></a></td><td>13-168</td></tr><tr><td>Smart Warmup UI（启用后默认勾选、至少保留 1 个）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/SmartWarmup.tsx#L14-L120" target="_blank" rel="noreferrer"><code>src/components/settings/SmartWarmup.tsx</code></a></td><td>14-120</td></tr><tr><td>配额治理配置字段（<code>quota_protection</code> / <code>scheduled_warmup</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/types/config.ts#L54-L94" target="_blank" rel="noreferrer"><code>src/types/config.ts</code></a></td><td>54-94</td></tr><tr><td>默认阈值与默认配置（<code>threshold_percentage: 10</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L20-L51" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>20-51</td></tr><tr><td>写入/恢复 <code>protected_models</code>（阈值判断与落盘）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L254-L467" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>254-467</td></tr><tr><td>请求侧配额保护过滤（<code>get_token(..., target_model)</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L470-L674" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>470-674</td></tr><tr><td>保护组归一化（<code>normalize_to_standard_id</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L230-L254" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>230-254</td></tr><tr><td>Smart Warmup 定时扫描（10 分钟一次 + 4 小时冷却 + <code>warmup_history.json</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/scheduler.rs#L11-L221" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/scheduler.rs</code></a></td><td>11-221</td></tr><tr><td>手动预热命令（<code>warm_up_all_accounts</code> / <code>warm_up_account</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L167-L212" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>167-212</td></tr><tr><td>预热实现（调用内部端点 <code>/internal/warmup</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/quota.rs#L271-L512" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/quota.rs</code></a></td><td>271-512</td></tr><tr><td>内部预热端点实现（构造请求 + 调用上游）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/warmup.rs#L3-L220" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/warmup.rs</code></a></td><td>3-220</td></tr></tbody></table></details>',71)])])}const h=o(d,[["render",c]]);export{m as __pageData,h as default};
